class VectorClock {
  constructor(nodeId, nodeIds) {
    this.nodeId = nodeId;
    this.v = Object.fromEntries(nodeIds.map(n => [n, 0]));
  }
  // Local event on this node.
  tick() { this.v[this.nodeId] += 1; return this; }
  // Merge a received clock, then advance our own slot.
  update(other) {
    for (const n of Object.keys(this.v)) {
      this.v[n] = Math.max(this.v[n], other.v[n] ?? 0);
    }
    this.v[this.nodeId] += 1;
    return this;
  }
  clone() {
    const c = new VectorClock(this.nodeId, Object.keys(this.v));
    c.v = { ...this.v };
    return c;
  }
}

// Returns 'before' | 'after' | 'concurrent' | 'equal'
function compare(a, b) {
  const keys = new Set([...Object.keys(a.v), ...Object.keys(b.v)]);
  let aLeq = true, bLeq = true, equal = true;
  for (const k of keys) {
    const av = a.v[k] ?? 0, bv = b.v[k] ?? 0;
    if (av > bv) aLeq = false;
    if (bv > av) bLeq = false;
    if (av !== bv) equal = false;
  }
  if (equal) return 'equal';
  if (aLeq) return 'before';   // a <= b, not equal
  if (bLeq) return 'after';    // b <= a, not equal
  return 'concurrent';         // neither dominates
}

// --- Demonstration ---
const nodes = ['P1', 'P2', 'P3'];

// Causal chain: P1 writes msg, P2 receives and replies.
const p1 = new VectorClock('P1', nodes).tick();      // {P1:1,P2:0,P3:0}
const msg = p1.clone();                               // message carries p1's clock
const p2 = new VectorClock('P2', nodes).update(msg);  // {P1:1,P2:1,P3:0}
console.log(compare(msg, p2)); // 'before' -> reply causally after the message

// Concurrent writes: P1 and P3 act independently, never communicating.
const w1 = new VectorClock('P1', nodes).tick().tick(); // {P1:2,P2:0,P3:0}
const w3 = new VectorClock('P3', nodes).tick().tick().tick(); // {P1:0,P2:0,P3:3}
console.log(compare(w1, w3)); // 'concurrent' -> conflict to be resolved

// Orchestrated saga: a central coordinator drives the steps and compensations.
// Every command carries sagaId as an idempotency key; services dedupe on it.

const steps = [
  {
    name: 'payment',
    forward:  (ctx) => payment.charge({ idemKey: ctx.sagaId, amount: ctx.amount, card: ctx.card }),
    compensate:(ctx) => payment.refund({ idemKey: ctx.sagaId + ':refund' }),
  },
  {
    name: 'inventory',
    forward:  (ctx) => inventory.reserve({ idemKey: ctx.sagaId, sku: ctx.sku, qty: ctx.qty }),
    compensate:(ctx) => inventory.release({ idemKey: ctx.sagaId + ':release' }),
  },
  {
    name: 'shipping',
    forward:  (ctx) => shipping.createShipment({ idemKey: ctx.sagaId, address: ctx.address }),
    compensate:(ctx) => shipping.cancelShipment({ idemKey: ctx.sagaId + ':cancel' }),
  },
];

async function runSaga(ctx) {
  const completed = [];
  try {
    for (const step of steps) {
      // Forward step is idempotent: a retry with the same sagaId is a no-op server-side.
      await withRetry(() => step.forward(ctx));
      completed.push(step);
      await sagaLog.markCompleted(ctx.sagaId, step.name); // durable progress for crash recovery
    }
    return { status: 'COMPLETED' };
  } catch (err) {
    // Failure: compensate the already-completed steps in REVERSE order.
    for (const step of completed.reverse()) {
      // Compensations are idempotent and retried until they succeed.
      await withRetry(() => step.compensate(ctx));
      await sagaLog.markCompensated(ctx.sagaId, step.name);
    }
    return { status: 'ROLLED_BACK', failedAt: err.step ?? 'unknown' };
  }
}

// Simple bounded retry with backoff; relies on idempotency for safety.
async function withRetry(fn, attempts = 5) {
  let delay = 100;
  for (let i = 0; i < attempts; i++) {
    try { return await fn(); }
    catch (e) {
      if (i === attempts - 1) throw e;
      await new Promise(r => setTimeout(r, delay));
      delay *= 2; // exponential backoff; add jitter in production
    }
  }
}

// Example: if shipping.createShipment throws, runSaga compensates
// inventory.release then payment.refund, in that order.
